                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           async def test_login_empty_password(service_client) :response = await service_client.post(AUTH_LOGIN_URL, json = {"email" : "user@example.com", "password" : "", }, )

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                